using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Tool implementations -----------------------------------------------

var notepad = new Notepad();

[Description("Search the web for information on a given query. Returns a list of result snippets.")]
static async Task<string> SearchWeb(
    [Description("The search query string")] string query)
{
    // Uses the free DuckDuckGo Instant Answer API (no key required).
    using var http = new HttpClient();
    var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}&format=json&no_html=1";
    using var response = await http.GetAsync(url);
    response.EnsureSuccessStatusCode();

    var doc = await response.Content.ReadFromJsonAsync<JsonElement>();

    var results = new List<string>();

    // Abstract text (main instant answer)
    var abstractText = doc.GetProperty("AbstractText").GetString();
    if (!string.IsNullOrWhiteSpace(abstractText))
        results.Add($"[Abstract] {abstractText}");

    // Related topics
    if (doc.TryGetProperty("RelatedTopics", out var topics))
    {
        foreach (var topic in topics.EnumerateArray().Take(5))
        {
            var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
            if (!string.IsNullOrWhiteSpace(text))
                results.Add($"[Related] {text}");
        }
    }

    return results.Count > 0
        ? string.Join("\n\n", results)
        : "No results found. Try rephrasing the query.";
}

[Description("Save a research note. Use this to record key findings as you discover them.")]
string SaveNote(
    [Description("Short title for the note")] string title,
    [Description("The note content")] string content)
{
    return notepad.Save(title, content);
}

[Description("Retrieve all saved research notes so far.")]
string GetNotes()
{
    return notepad.GetAll();
}

// --- Build the AI agent --------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

var tools = new AITool[]
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(SaveNote),
    AIFunctionFactory.Create(GetNotes),
};

IChatClient client = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions { Tools = [.. tools] };

// --- Agent loop ----------------------------------------------------------

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptUser("What topic should I research?");

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your goal is to thoroughly research the given topic
        by searching the web multiple times with different queries, saving the most
        important findings as notes, and then producing a comprehensive summary.

        Workflow:
        1. Search for broad information on the topic.
        2. Identify interesting sub-topics and search for those as well.
        3. Save key findings using the SaveNote tool as you go.
        4. Perform at least 3 different searches before summarizing.
        5. After gathering enough information, retrieve your notes and write a final
           well-structured summary with sections, citing the facts you discovered.
        """),
    new(ChatRole.User, $"Please research the following topic: {topic}"),
};

var response = await client.GetResponseAsync(messages, chatOptions);

Console.WriteLine("\n━━━ Research Summary ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n");
Console.WriteLine(response.Text);
Console.WriteLine("\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n");

Console.WriteLine($"📝 {notepad.Count} note(s) saved during research.");

// --- Helpers -------------------------------------------------------------

static string PromptUser(string prompt)
{
    Console.Write($"{prompt} ");
    var input = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(input))
    {
        Console.WriteLine("No topic provided. Exiting.");
        Environment.Exit(1);
    }
    return input;
}

// --- Notepad tool state --------------------------------------------------

sealed class Notepad
{
    private readonly List<(string Title, string Content)> _notes = [];

    public int Count => _notes.Count;

    public string Save(string title, string content)
    {
        _notes.Add((title, content));
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    public string GetAll()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"--- Note #{i + 1}: {n.Title} ---\n{n.Content}"));
    }
}

